var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"로널드 박사님! 로널드 박사님!","JPN":"ロナルド博士！　ロナルド博士！","ENG":"Dr. Ronald! Dr. Ronald!","TWN":"博士！羅那魯多·李博士！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"틀렸어! 고치 관측소와 연결이 안 돼! 무슨 일이 생긴 건가?","JPN":"ダメだ！　繭観測所と繋がらない！　何かあったのかしら？","ENG":"Ugh! It's not connecting us to the cocoon observatory! What's going on over there?","TWN":"不行！無法接通繭觀測站！發生什麼事了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"얼레? 근데 뭔가 침식체 녀석들의 움직임이 이상한데?","JPN":"あれ？　でも何だか侵食体の連中の動きがおかしいわね？","ENG":"Huh? But the movement of those C.O.s are kinda weird.","TWN":"喔？這裡的侵蝕體行為有些奇怪？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"고치가 있는 곳으로부터 침식체가 무리를 지어 어디론가 이동하고 있어.","JPN":"繭のある場所から侵食体が群れを成してどこかに移動してる。","ENG":"The C.O.s are moving away in hordes from where the cocoon is.","TWN":"他們正從繭所在的地方，成群結隊地往某個地方移動。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설마 카운터가 없는 틈을 타서 거점 기지를 습격했다고?","JPN":"まさかカウンターの不在をついて拠点基地を襲ったというの？","ENG":"Did they ambush the base while no Counter was present?","TWN":"難道他們想趁著制裁者不在，襲擊據點基地?"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"침식체가 양동작전 같은 걸 펼칠 수 있을 리가…….","JPN":"侵食体に陽動作戦なんて使えるわけが……","ENG":"There's no way C.O.s can pull off a feint operation...","TWN":"侵蝕體還會聲東擊西……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원, 현장에서 관측된 개체를 <color=#ffd34c>아종 네피림</color>으로 간주!","JPN":"全隊員、現場で観測された個体を<color=#ffd34c>亜種ネフィリム</color>と見なします！","ENG":"All units, the creature observed on the field will be considered a <color=#ffd34c>Nephil subspecies</color>!","TWN":"全體隊員，現場觀測到的個體歸類為<color=#ffd34c>亞種諾菲力</color>！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현 시간부로, 긴급 작전 태세에 돌입합니다!","JPN":"現時刻より、緊急作戦体制に突入します！","ENG":"From this point on, we are on emergency alert!","TWN":"即刻起，進入緊急作戰狀態！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사이버캣, 지금 즉시 공간 도약을 준비하세요! 본부로 돌아가겠습니다!","JPN":"サイバーキャット、今すぐに空間跳躍の準備をしてください！　本部に帰還します！","ENG":"Cyber Cat, prepare for an immediate space jump! We head back to HQ!","TWN":"賽博貓，現在立刻準備進行跳躍！返回總部！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"알겠어! 공간 도약 시퀸스 준비!","JPN":"わかったわ！　空間跳躍シークエンス準備！","ENG":"Roger! Preparing the space jump sequence!","TWN":"明白！空間跳躍程式準備！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"공간 도약 스타트!","JPN":"空間跳躍、開始！","ENG":"Initiating the space jump!","TWN":"空間跳躍啟動！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Kgh!","TWN":"呃？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"윽!! 무슨 일이에요, 사이버캣! 상황 보고하세요!","JPN":"くっ！！　何が起きたんですか、サイバーキャット！　状況報告を！","ENG":"Ngh!! Report, Cyber Cat! What just happened?!","TWN":"怎麼了，賽博貓！報告情況！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"나도 몰라! 공간 도약은 정상적으로 진행 중, 이미 초공간에 돌입했어!","JPN":"アタシにもよくわからないわ！　空間跳躍は正常に進行中、すでに超空間に突入してる！","ENG":"I dunno! The space jump is operating normally and we've already entered hyperspace!","TWN":"我也不知道！空間跳躍正常進行中，已進入超空間！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"아마도 이런 충격이면, 공간 도약 직전에 무언가와 충돌한 것 같은데?","JPN":"たぶん今の衝撃は空間跳躍の直前に何かと衝突したんじゃない？","ENG":"With an impact like this, we must have collided with something right before the space jump.","TWN":"不過這種衝擊，也許是跳躍之前與某種東西發生了碰撞？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};